import Hatchet from '@hatchet-dev/typescript-sdk';

const hatchet = Hatchet.init();

const StandardSleepWorkflow = {
  id: 'standard-sleep-workflow',
  description: 'A workflow that sleeps using standard blocking wait',
  on: {
    event: 'standard:sleep',
  },
  steps: [
    {
      name: 'standard-sleep-step',
      run: async (ctx: any) => {
        console.log('StandardSleepTask started, holding slot...');
        await new Promise((resolve) => setTimeout(resolve, 5000));
        console.log('StandardSleepTask finished.');
        return { status: 'completed' };
      },
    },
  ],
};

const DurableSleepWorkflow = {
  id: 'durable-sleep-workflow',
  description: 'A workflow that sleeps using durable sleepFor',
  on: {
    event: 'durable:sleep',
  },
  steps: [
    {
      name: 'durable-sleep-step',
      run: async (ctx: any) => {
        console.log('DurableSleepTask started, releasing slot...');
        await ctx.sleepFor('5s');
        console.log('DurableSleepTask finished.');
        return { status: 'completed' };
      },
    },
  ],
};

const TestWorkflow = {
  id: 'test-workflow',
  description: 'A test workflow to check slot availability',
  on: {
    event: 'test:task',
  },
  steps: [
    {
      name: 'test-step',
      run: async (ctx: any) => {
        console.log('TestTask executed!');
        return { status: 'executed' };
      },
    },
  ],
};

async function main() {
  const worker = await hatchet.worker('slot-manager-worker', {
    maxRuns: 1, // Concurrency limit of 1
  });

  await worker.registerWorkflow(StandardSleepWorkflow as any);
  await worker.registerWorkflow(DurableSleepWorkflow as any);
  await worker.registerWorkflow(TestWorkflow as any);

  console.log('Worker started with concurrency limit 1...');
  await worker.start();
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

import Hatchet from '@hatchet-dev/typescript-sdk';
import { spawn } from 'child_process';

const hatchet = Hatchet.init();

async function sleep(ms: number) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function main() {
  console.log('Starting worker in background...');
  const workerProcess = spawn('npx', ['ts-node', 'worker.ts'], {
    stdio: 'inherit',
    env: process.env,
  });

  // Give the worker some time to register and start
  await sleep(5000);

  console.log('\n--- Scenario 1: Standard Sleep (Blocking) ---');
  console.log('Triggering StandardSleepTask...');
  await hatchet.event.push('standard:sleep', {});
  await sleep(500); // Small gap
  console.log('Triggering TestTask (should be blocked)...');
  await hatchet.event.push('test:task', {});

  // Wait for Scenario 1 to complete (Standard sleep 5s + TestTask)
  await sleep(10000);

  console.log('\n--- Scenario 2: Durable Sleep (Non-blocking) ---');
  console.log('Triggering DurableSleepTask...');
  await hatchet.event.push('durable:sleep', {});
  await sleep(500); // Small gap
  console.log('Triggering TestTask (should execute immediately)...');
  await hatchet.event.push('test:task', {});

  // Wait for Scenario 2 to complete
  await sleep(10000);

  console.log('\nDemonstration complete. Killing worker...');
  workerProcess.kill();
  process.exit(0);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

